async (params, browser) => {
  // Open Discord server
  await browser.open(`${params.server_url}`)

  // Wait for Discord to load
  await browser.waitForSelector('div[role=\'textbox\']', 15000)

  await browser.wait(1500)

  // Open search
  const open_search = await browser.evaluate(`const searchBtn = document.querySelector('button[aria-label="Search"]'); if (searchBtn) { searchBtn.click(); } else { const toolbar = document.querySelector('[class*="toolbar"]'); if (toolbar) { const btns = toolbar.querySelectorAll('button'); for (const b of btns) { if (b.querySelector('svg') && b.getAttribute('aria-label')?.toLowerCase().includes('search')) { b.click(); break; } } } } return { clicked: true }`)

  await browser.wait(1000)

  // Type search query
  const type_search = await browser.evaluate(`const query = params.query; const searchInput = document.querySelector('input[aria-label="Search"], input[placeholder="Search"]'); if (searchInput) { searchInput.focus(); const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSetter.call(searchInput, query); searchInput.dispatchEvent(new Event('input', {bubbles: true})); searchInput.dispatchEvent(new Event('change', {bubbles: true})); await new Promise(r => setTimeout(r, 500)); searchInput.dispatchEvent(new KeyboardEvent('keydown', {key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true})); } return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const searchPanel = document.querySelector('[aria-label="Search Results"]') || document.querySelector('[class*="searchResult"]')?.closest('[role="list"]') || document.body; const msgEls = searchPanel.querySelectorAll('li[id^="search-result-"], div[id^="search-result-"]'); if (msgEls.length > 0) { for (let i = 0; i < Math.min(msgEls.length, 10); i++) { const el = msgEls[i]; const authorEl = el.querySelector('span[id^="message-username-"]') || el.querySelector('h3 span'); const contentEl = el.querySelector('div[id^="message-content-"]'); const timeEl = el.querySelector('time'); results.push({ author: authorEl ? authorEl.textContent.trim() : '', content: contentEl ? contentEl.textContent.trim() : '', timestamp: timeEl ? timeEl.getAttribute('datetime') || '' : '' }); } } else { const allMsgContent = document.querySelectorAll('div[id^="message-content-"]'); for (let i = 0; i < Math.min(allMsgContent.length, 10); i++) { const contentEl = allMsgContent[i]; const container = contentEl.closest('li') || contentEl.closest('div[role="listitem"]'); const authorEl = container ? container.querySelector('span[id^="message-username-"]') || container.querySelector('h3 span') : null; const timeEl = container ? container.querySelector('time') : null; results.push({ author: authorEl ? authorEl.textContent.trim() : '', content: contentEl.textContent.trim(), timestamp: timeEl ? timeEl.getAttribute('datetime') || '' : '' }); } } return { result_count: results.length, results: results }`)

  return search_results
}
